class Solution {
public:
  string eulerianCircuit(vector<vector<int>>& g) {
    if (g.size() % 2 == 1) return "";
    for (int i = 0; i < g.size(); i++) {
      if (g[i].size() % 2 == 1) return "";
    }
    // TO DO: implement actual Eulerian circuit traversal

    // Start from any vertex in a graph and use DFS to traverse it.
    int startVertex = 0;
    vector<int> visited(g.size(), 0);
    vector<int> circuit;
    dfs(startVertex, -1, g, visited, circuit);

    string result = "";
    for (int v : circuit) {
      result += to_string(v + 1) + " ";
    }
    return result;

    void dfs(int currentVertex, int prevVertex, vector<vector<int>>& g, vector<int>& visited, vector<int>& circuit) {
      visited[currentVertex] = 1;
      circuit.push_back(currentVertex);
      for (int i = 0; i < g[currentVertex].size(); i++) {
        if (g[currentVertex][i] == 1 && visited[i] == 0) {
          dfs(i, currentVertex, g, visited, circuit);
        } else if (g[currentVertex][i] == 1 && visited[i] == 1) {
          circuit.push_back(i);
        }
      }
    }
  }
};

