public class Solution {
  public String eulerianCircuit(int[][] g) {
    if (g.length % 2 == 1) return "";
    for (int[] edge : g) {
      if (edge.length % 2 == 1) return "";
    }
    // TO DO: implement actual Eulerian circuit traversal

    // Start from any vertex in a graph and use DFS to traverse it.
    int startVertex = 0;
    boolean[] visited = new boolean[g.length];
    List<Integer> circuit = new ArrayList<>();
    dfs(startVertex, -1, g, visited, circuit);

    String result = "";
    for (int v : circuit) {
      result += (v + 1) + " ";
    }
    return result;

    void dfs(int currentVertex, int prevVertex, int[][] g, boolean[] visited, List<Integer> circuit) {
      visited[currentVertex] = true;
      circuit.add(currentVertex);
      for (int i = 0; i < g[currentVertex].length; i++) {
        if (g[currentVertex][i] == 1 && !visited[i]) {
          dfs(i, currentVertex, g, visited, circuit);
        } else if (g[currentVertex][i] == 1 && visited[i]) {
          circuit.add(i);
        }
      }
    }
  }
}

